import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useCart } from "../context/CartContext";
import { useAuth } from "../context/AuthContext";
import api from "../utils/api";
import { toast } from "react-toastify";
import "./Checkout.css";

function Checkout() {
  const { cart, totalPrice, clearCart } = useCart();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [shipping, setShipping] = useState({
    address: "",
    city: "",
    postalCode: "",
    country: "",
  });
  const [paymentMethod, setPaymentMethod] = useState("Card");

  if (!user) {
    navigate("/login");
    return null;
  }
  if (cart.length === 0) {
    navigate("/cart");
    return null;
  }

  const shippingCost = totalPrice > 50 ? 0 : 8;
  const tax = totalPrice * 0.1;
  const grandTotal = totalPrice + shippingCost + tax;

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await api.post("/orders", {
        orderItems: cart.map((i) => ({
          product: i._id,
          name: i.name,
          image: i.image,
          price: i.price,
          qty: i.qty,
        })),
        shippingAddress: shipping,
        paymentMethod,
        itemsPrice: totalPrice,
        shippingPrice: shippingCost,
        taxPrice: tax,
        totalPrice: grandTotal,
      });
      clearCart();
      toast.success("Order placed successfully!");
      navigate("/orders");
    } catch (err) {
      toast.error(err.response?.data?.message || "Order failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="checkout-page fade-in">
      <div className="container">
        <h1 className="page-title">Checkout</h1>
        <form onSubmit={handleSubmit} className="checkout-grid">
          <div className="checkout-form">
            <div className="checkout-section">
              <h3>Shipping Address</h3>
              <div className="form-group">
                <label className="form-label">Address</label>
                <input
                  className="form-input"
                  required
                  value={shipping.address}
                  onChange={(e) =>
                    setShipping({ ...shipping, address: e.target.value })
                  }
                />
              </div>
              <div className="form-row">
                <div className="form-group">
                  <label className="form-label">City</label>
                  <input
                    className="form-input"
                    required
                    value={shipping.city}
                    onChange={(e) =>
                      setShipping({ ...shipping, city: e.target.value })
                    }
                  />
                </div>
                <div className="form-group">
                  <label className="form-label">Postal Code</label>
                  <input
                    className="form-input"
                    required
                    value={shipping.postalCode}
                    onChange={(e) =>
                      setShipping({ ...shipping, postalCode: e.target.value })
                    }
                  />
                </div>
              </div>
              <div className="form-group">
                <label className="form-label">Country</label>
                <input
                  className="form-input"
                  required
                  value={shipping.country}
                  onChange={(e) =>
                    setShipping({ ...shipping, country: e.target.value })
                  }
                />
              </div>
            </div>

            <div className="checkout-section">
              <h3>Payment Method</h3>
              <div className="payment-options">
                {["Card", "PayPal", "COD"].map((m) => (
                  <label
                    key={m}
                    className={`payment-option ${paymentMethod === m ? "active" : ""}`}
                  >
                    <input
                      type="radio"
                      name="pay"
                      value={m}
                      checked={paymentMethod === m}
                      onChange={(e) => setPaymentMethod(e.target.value)}
                    />
                    <span>{m === "COD" ? "Cash on Delivery" : m}</span>
                  </label>
                ))}
              </div>
            </div>
          </div>

          <aside className="cart-summary">
            <h3>Order Summary</h3>
            {cart.map((i) => (
              <div key={i._id} className="checkout-item">
                <img src={i.image} alt={i.name} />
                <div>
                  <strong>{i.name}</strong>
                  <small>Qty: {i.qty}</small>
                </div>
                <span>${(i.price * i.qty).toFixed(2)}</span>
              </div>
            ))}
            <div className="summary-divider"></div>
            <div className="summary-row">
              <span>Subtotal</span>
              <span>${totalPrice.toFixed(2)}</span>
            </div>
            <div className="summary-row">
              <span>Shipping</span>
              <span>
                {shippingCost === 0 ? "Free" : `$${shippingCost.toFixed(2)}`}
              </span>
            </div>
            <div className="summary-row">
              <span>Tax</span>
              <span>${tax.toFixed(2)}</span>
            </div>
            <div className="summary-divider"></div>
            <div className="summary-row total">
              <span>Total</span>
              <span>${grandTotal.toFixed(2)}</span>
            </div>
            <button
              type="submit"
              className="btn btn-primary btn-block btn-lg"
              disabled={loading}
            >
              {loading ? "Placing order..." : "Place Order1"}
            </button>
          </aside>
        </form>
      </div>
    </div>
  );
}

export default Checkout;
